for (let [mac, active_xweb] of entries(xalarms)) {
    if (active_xweb.active_devices.length == 0) continue;
    let setup_xweb = getSetup(xgetsetup[mac]) || {}
    let sysinfo_xweb = getSysinfo(xsysinfo[mac]) || {}
    let { devices } = active_xweb
    let alarm_devices = entries(devices).filter(([, d]) => d.active_alarms.length)
    let { stream_data } = xstream[mac]
    if (!stream_data) continue;
    let serverTime = new Date().getTime()
    let { stream } = stream_data, { ts: localTime } = stream || {};
    (localTime && (localTime *= 1000)) || (!localTime && (localTime = serverTime));
    for (let [did, dev] of alarm_devices) {
        let def_dev = levelsDef[setup_xweb.devices[did]?.gen.name] || {};
        let alarms = entries(dev.alarms)
            .map(([pointId, point]) => { return { pointId, ...point } })
            .filter(a => a.en)
        for (let al of alarms) {
            let index = `${mac}_${did}_${al.pointId}`;
            let level = def_dev[al.pointId]?.level ? parseInt(def_dev[al.pointId]?.level) : 3;
            al.value = al.value > 0 ? true : false;

            if (al.value) {
                if (!process_status[index]) {
                    let activePayload = {
                        store_name: decode(sysinfo_xweb.info.name),
                        mac_address: mac,
                        device_name: decode(setup_xweb.devices[did]?.gen.name),
                        device_adr: setup_xweb.devices[did]?.gen.addr2,
                        uid: setup_xweb.devices[did]?.gen.uiddev,
                        alarm_name: decode(al.name),
                        point_id: al.pointId,
                        value: true,
                        level: level,
                        dateStart: serverTime,
                        localTime,
                        process: available_states.map((item, i) => {
                            let includes_label = (item.label).includes("alarm_created");
                            let split_label = parseInt((item.label).split("lv")[1]);
                            return {
                                id_arr: i,
                                index: index,
                                label: item.label,
                                showLabel: item.showLabel,
                                status: (includes_label ? split_label !== undefined ? split_label == level : level ? true : false : false) ? true : false,
                                statusShow: true,
                                timestamp: split_label == level ? process_status[index] ? process_status[index]?.dateStart : serverTime : null,
                            }
                        })
                    }
                    process_status[index] = activePayload;
                } else {
                    if (!(process_status[index].value)) {
                        let hasKeyActive = {
                            ...process_status[index],
                            value: true,
                            level: level,
                            dateStart: serverTime,
                            localTime,
                            process: available_states.map((item, i) => {
                                let includes_label = (item.label).includes("alarm_created");
                                let split_label = parseInt((item.label).split("lv")[1]);
                                return {
                                    id_arr: i,
                                    index: index,
                                    label: item.label,
                                    showLabel: item.showLabel,
                                    status: (includes_label ? split_label !== undefined ? split_label == level : level ? true : false : false) ? true : false,
                                    statusShow: true,
                                    timestamp: split_label == level ? process_status[index] ? process_status[index]?.dateStart : serverTime : null,
                                }
                            })
                        }
                        process_status[index] = hasKeyActive;
                    }
                }
            } else {
                if (process_status[index] && process_status[index].value) {
                    process_status[index].value = false;
                    process_status[index].process = (process_status[index].process).map((item, i) => {
                        return {
                            id_arr: i,
