const decode = (text) => decodeURIComponent(text);

let Active = {};
let Stop = {};

const SEVEN_DAYS = 7 * 24 * 60 * 60 * 1000;

let config = msg.config_url;
const compareVendor = (mac) => {
    if (!config) return;
    return config.find((x) => x.mac_address == mac);
}

for (let [mac, active_xweb] of entries(xalarms)) {
    let setup_xweb = getSetup(xgetsetup[mac]) || {}
    let sysinfo_xweb = getSysinfo(xsysinfo[mac]) || {}
    let { devices } = active_xweb
    let { stream_data } = xstream[mac]
    if (!stream_data) continue;
    let serverTime = new Date().getTime()
    let { stream } = stream_data, { ts: localTime } = stream || {};

    (localTime && (localTime *= 1000)) || (!localTime && (localTime = serverTime));
    for (let [did, dev] of entries(devices)) {
        let alarms = entries(dev.alarms)
            .map(([pointId, point]) => { return { pointId, ...point } })
            .filter(a => a.en)
        for (let al of alarms) {
            let index = `${mac}_${did}_${al.pointId}`;
            al.value = al.value > 0 ? true : false;

            let vendor = compareVendor(mac);

            // Case 1: Alarm Active
            if (al.value) {

                // node.status({ fill: "red", shape: "ring", text: "Active " + decode(al.name) + " [" + vendor.owner + "]" });
                if (!Active_Alarms[index]) {
                    Active[index] = {
                        store_name: decode(sysinfo_xweb.info.name),
                        mac_address: mac,
                        vendor: vendor.owner,
                        device_name: decode(setup_xweb.devices[did].gen.name),
                        device_adr: setup_xweb.devices[did].gen.addr2,
                        device_type: context.getDeviceType(decode(setup_xweb.devices[did].gen.name)),//tn:
                        uid: did,
                        alarm_name: decode(al.name),
                        dateStart: localTime,
                        value: true,
                    }
                    Active_Alarms[index] = Active[index];
                } else {
                    if (!(Active_Alarms[index].value)) {
                        Active_Alarms[index].vendor = vendor.owner;
                        Active_Alarms[index].dateStart = localTime;
                        Active_Alarms[index].value = true;
                        Active[index] = Active_Alarms[index]
                    }
                }
            } else {
                if (Active_Alarms[index]) {
                    if (Active_Alarms[index].value) {
                        // node.status({ fill: "green", shape: "ring", text: "Stop " + decode(al.name) + " [" + vendor.owner + "]" });

                        Active_Alarms[index] = {
                            ...Active_Alarms[index],
                            value: false,
                            dateEnd: serverTime,
                            note: chk_watch[index]?.acknow > 0 ? chk_watch[index]?.note : (chk_watch[index]?.note !== "Acknow") ? "Normal" : "Startup",
                            dateAcknow: chk_watch[index]?.timestamp,
                        };
                        Stop[index] = Active_Alarms[index]
                        delete chk_watch[index];
                    } else {
                        if (Active_Alarms[index].dateEnd) {
                            // clear cache every 7 days
                            let diff = serverTime - Active_Alarms[index].dateEnd;
                            if (diff > SEVEN_DAYS) {
                                delete Active_Alarms[index];
                            }
                        }
                    }
                }
            }
        }
    }
}
msg.payload = [...Object.values(Active), ...Object.values(Stop)]
return msg;

