    let store = ensureStore(xgetsetup, mac);
    const { alarmCategories: _ac, maps: _maps, dpu: _dpu, devices, ...restSetup } = data || {};

    let cleanDevices = undefined;
    if (devices) {
        cleanDevices = {};
        for (const [devKey, devVal] of Object.entries(devices)) {
            if (!devVal) continue;

            const { cmds: _cmds, lng, gen, vrs, ...restDev } = devVal;

            let cleanLng = undefined;
            if (lng) {
                const { cmds: _lngCmds, ...restLng } = lng;
                cleanLng = restLng;
            }

            let cleanGen = undefined;
            if (gen) {
                const { devcom: _dc, dixelldev: _dd, dstp: _ds, desc: _desc, ...restGen } = gen;
                cleanGen = restGen;
            }

            let cleanVrs = undefined;
            if (vrs) {
                cleanVrs = {};
                for (const [vrsKey, vrsVal] of Object.entries(vrs)) {
                    if (!vrsVal) continue;
                    const { cwi: _cwi, chartDef, ...restVrsVal } = vrsVal;

                    let cleanChartDef = undefined;
                    if (chartDef) {
                        const { color: _color, ...restChartDef } = chartDef;
                        cleanChartDef = restChartDef;
                    }

                    cleanVrs[vrsKey] = {
                        ...restVrsVal,
                        ...(cleanChartDef && { chartDef: cleanChartDef })
                    };
                }
            }

            cleanDevices[devKey] = {
                ...restDev,
                ...(cleanLng && { lng: cleanLng }),
                ...(cleanGen && { gen: cleanGen }),
                ...(cleanVrs && { vrs: cleanVrs })
            };
        }
    }

    store.setup_data = {
        mac,
        ts: Date.now(),
        ...shallowCopy(restSetup),
        ...(cleanDevices && { devices: safeClone(cleanDevices) })
    };

    delete currentContext.setup_err;
    delete store?.setup_err;

    let hasError = data.error;
    data = null;
    cleanDevices = null;

    n && node.send({ payload: "setup processed", topic: "getsetup" });

    if (hasError === "PERMISSION_DENIED") {
        return await login(endpointConfig, getsetup);
    }

    updateThread(mac, { getsetupIsRequired: false });
    return statusWithTs("ok", mac, "getsetup", host);
}

const streamOnData = (currentContext, endpointConfig) => async (data) => {
    let { mac } = currentContext;
    let { host } = endpointConfig;

    let store = ensureStore(xstream, mac);

    // Filter: stream.inputs, stream.outputs
